// Firebase Messaging Service Worker
// This runs in the background to receive push notifications when the app is closed

importScripts(
  "https://www.gstatic.com/firebasejs/11.9.1/firebase-app-compat.js",
);
importScripts(
  "https://www.gstatic.com/firebasejs/11.9.1/firebase-messaging-compat.js",
);

// Load Firebase config from runtime config.js (generated by docker-entrypoint.sh)
// This ensures credentials are NOT baked into the service worker at build time
let firebaseApp = null;
let messaging = null;

// Fetch runtime config and initialize Firebase
fetch('/config.js')
  .then(response => response.text())
  .then(scriptContent => {
    // Execute the config.js script to populate window.RUNTIME_CONFIG
    eval(scriptContent);
    
    if (self.RUNTIME_CONFIG) {
      firebaseApp = firebase.initializeApp({
        apiKey: self.RUNTIME_CONFIG.FIREBASE_API_KEY,
        authDomain: self.RUNTIME_CONFIG.FIREBASE_AUTH_DOMAIN,
        projectId: self.RUNTIME_CONFIG.FIREBASE_PROJECT_ID,
        storageBucket: self.RUNTIME_CONFIG.FIREBASE_STORAGE_BUCKET,
        messagingSenderId: self.RUNTIME_CONFIG.FIREBASE_MESSAGING_SENDER_ID,
        appId: self.RUNTIME_CONFIG.FIREBASE_APP_ID,
      });
      
      messaging = firebase.messaging();
      console.log('Firebase initialized in service worker with runtime config');
    } else {
      console.error('RUNTIME_CONFIG not found in config.js');
    }
  })
  .catch(error => {
    console.error('Failed to load runtime config in service worker:', error);
  });

// Handle background messages (when app is not in focus)
// Note: messaging is initialized asynchronously, so we set up the handler after initialization
setTimeout(() => {
  if (messaging) {
    messaging.onBackgroundMessage((payload) => {
      const { title, body, icon } = payload.notification || {};

      self.registration.showNotification(title || "GearShare", {
        body: body || "You have a new notification",
        icon: icon || "/vite.svg",
        badge: "/vite.svg",
        data: payload.data,
        actions: [{ action: "open", title: "Open App" }],
      });
    });
  }
}, 1000); // Wait for initialization to complete

// Handle notification click
self.addEventListener("notificationclick", (event) => {
  event.notification.close();

  // Open the app when notification is clicked
  event.waitUntil(
    clients
      .matchAll({ type: "window", includeUncontrolled: true })
      .then((clientList) => {
        // If app is already open, focus it
        for (const client of clientList) {
          if (client.url.includes(self.location.origin) && "focus" in client) {
            return client.focus();
          }
        }
        // Otherwise open a new window
        return clients.openWindow("/requests");
      }),
  );
});
